mapper.select:
SELECT ka.article_id AS articleId, ka.author_id AS authorId, e.employee_name AS authorName, ka.article_title AS articleTitle, ka.article_category AS articleCategory, ka.article_status AS articleStatus, ka.view_count AS viewCount, ka.created_at AS createdAt FROM knowledge_article ka LEFT JOIN employee e ON ka.author_id = e.employee_id WHERE 1 = 1
AND ka.is_deleted = false
AND ( ka.author_id = #{requesterId} OR ka.article_status = 'APPROVED' )
AND ka.article_status != 'DRAFT'
AND ka.article_category = #{category}
AND ka.article_status = #{status}
AND ka.article_id = #{articleIdKeyword}
AND e.employee_name LIKE CONCAT('%', #{keyword}, '%')
AND ka.article_title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ka.view_count DESC
ORDER BY ka.created_at DESC
LIMIT #{size} OFFSET #{page} * #{size}

SELECT ka.article_id AS articleId, ka.author_id AS authorId, e.employee_name AS authorName, ka.article_title AS articleTitle, ka.article_category AS articleCategory, ka.article_status AS articleStatus, ka.view_count AS viewCount, ka.created_at AS createdAt FROM knowledge_article ka LEFT JOIN employee e ON ka.author_id = e.employee_id WHERE ka.is_deleted = false AND ka.article_status = 'PENDING'
AND ka.article_category = #{category}
AND ka.article_id = #{articleIdKeyword}
AND e.employee_name LIKE CONCAT('%', #{keyword}, '%')
AND ka.article_title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ka.view_count DESC
ORDER BY ka.created_at DESC
LIMIT #{size} OFFSET #{page} * #{size}

SELECT ka.article_id AS articleId, ka.article_title AS articleTitle, ka.article_category AS articleCategory, ka.article_status AS articleStatus, ka.equipment_id AS equipmentId, eq.equipment_name AS equipmentName, ka.article_content AS articleContent, ka.view_count AS viewCount, 0 AS commentCount, 0 AS reuseCount, ka.created_at AS createdAt, ka.updated_at AS updatedAt FROM knowledge_article ka LEFT JOIN equipment eq ON ka.equipment_id = eq.equipment_id WHERE ka.author_id = #{authorId} AND ka.is_deleted = false
AND ka.article_status = #{status}
ORDER BY ka.created_at DESC
LIMIT #{size} OFFSET #{offset}
